challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The UPF is overwhelmed by a massive flood of GTP-U traffic, causing it to drop packets, including RTP media for VoNR calls. This is breaking the media plane and causing call failures.",
      "primary_suspect_nf": "upf",
      "probes": [
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds=60",
          "expected_if_hypothesis_holds": "The UPF's data plane gauges show a significant packet loss rate (>10%) and a correspondingly low Mean Opinion Score (MOS).",
          "falsifying_observation": "The UPF's gauges show little to no packet loss (<1%) and a good MOS. This would indicate the UPF itself is not the source of packet loss."
        },
        {
          "tool": "get_network_status",
          "args_hint": "N/A; check all containers",
          "expected_if_hypothesis_holds": "The 'upf' container is in a 'running' state. The hypothesis is about overload, not a crash.",
          "falsifying_observation": "The 'upf' container is in an 'exited' or other non-running state. This would indicate a crash, a different failure mode than overload."
        },
        {
          "tool": "get_flows_through_component",
          "args_hint": "component=upf",
          "expected_if_hypothesis_holds": "Multiple flows, especially 'pdu_session_establishment' and 'vonr_call_setup', are listed as passing through the UPF.",
          "falsifying_observation": "No flows are listed for the UPF. This would suggest a major misconfiguration or a control plane failure preventing any sessions from being set up, which is a different problem than a data plane overload."
        }
      ],
      "notes": "This plan focuses on verifying the two main claims of the hypothesis: 1) the UPF is dropping packets, and 2) this is due to traffic overload, not a simple crash. Probes check the data plane state directly and verify the component's liveness."
    },
    {
      "hypothesis_id": "h2",
      "hypothesis_statement": "RTPEngine is experiencing an internal fault causing it to drop a high volume of RTP packets, leading to a high packet loss ratio and failed calls. This is a localized media-plane issue.",
      "primary_suspect_nf": "rtpengine",
      "probes": [
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds=60",
          "expected_if_hypothesis_holds": "RTPEngine's data plane gauges show a significant packet loss rate (>10%) and a low MOS.",
          "falsifying_observation": "RTPEngine's gauges show low packet loss (<1%). This would directly contradict the hypothesis that RTPEngine is dropping packets."
        },
        {
          "tool": "get_network_status",
          "args_hint": "N/A; check all containers",
          "expected_if_hypothesis_holds": "The 'rtpengine' container is 'running'. The hypothesis suggests an internal fault causing packet drops, not a container crash.",
          "falsifying_observation": "The 'rtpengine' container is 'exited' or in another non-running state, which would be a different failure mode."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from='upf', to_ip='rtpengine_ip'",
          "expected_if_hypothesis_holds": "A clean RTT (<5ms, 0% loss) from the UPF to RTPEngine. This would suggest the network path is healthy and packets are arriving at RTPEngine, implying any drops are happening inside RTPEngine itself.",
          "falsifying_observation": "High packet loss or latency is observed. This would suggest a network issue between the UPF and RTPEngine, rather than an internal RTPEngine fault."
        }
      ],
      "notes": "This plan attempts to isolate the fault to RTPEngine. It checks RTPEngine's own data plane metrics for loss and then uses a connectivity check from the upstream UPF to rule out a network path issue. This triangulation is key to distinguishing an RTPEngine-specific problem from a broader network failure."
    }
  ]
}

